const sites = ['indeed', 'linkedin', 'zip_recruiter', 'glassdoor', 'google'];

const sleep = (ms) => new Promise(resolve => {
  const start = Date.now();
  while (Date.now() - start < ms) {}
});

const allTerms = [
  // General terms
  $input.first().json.software_job,
  $input.first().json.devops_job,
  $input.first().json.fullstack_job,
  $input.first().json.remote_job,
  $input.first().json.associate_job,
  'backend developer python nodejs entry level',
  'frontend developer react javascript entry level',
  // Extra terms
  'associate software engineer',
  'associate software developer',
  'associate full stack developer',
  'associate backend developer',
  'associate frontend developer',
  'associate devops engineer',
  'software engineer new grad',
  'software engineer I entry level',
  'junior software engineer',
  'SDE 1 software engineer',
  'early career software engineer',
  'new graduate software engineer'
];

const apiKey = 'jobspy123';
const config = $input.first().json;

// Build all combinations upfront
const combinations = [];
for (const site of sites) {
  for (const term of allTerms) {
    combinations.push({ site, term });
  }
}

// Helper to fetch one combination
const fetchJobs = async ({ site, term }) => {
  try {
    const params = [
      `site_name=${encodeURIComponent(site)}`,
      `search_term=${encodeURIComponent(term)}`,
      `location=${encodeURIComponent(config.location)}`,
      `results_wanted=5`,
      `job_type=fulltime`,
      `country_indeed=USA`,
      `hours_old=168`
    ].join('&');

    const response = await helpers.httpRequest({
      method: 'GET',
      url: `https://prathik-jobspy.fly.dev/api/v1/search_jobs?${params}`,
      headers: { 'x-api-key': apiKey }
    });

    if (response.jobs && response.jobs.length > 0) {
      return response.jobs.map(job => ({
        title:       job.title        || '',
        company:     job.company      || '',
        location:    job.location     || '',
        job_url:     job.job_url      || '',
        description: (job.description || '').substring(0, 3000),
        salary:      job.min_amount   ? `$${job.min_amount} - $${job.max_amount}` : 'Not specified',
        date_posted: job.date_posted  || '',
        is_remote:   job.is_remote    || false,
        source:      site
      }));
    }
    return [];
  } catch(e) {
    console.log(`Failed: ${site} - ${term}: ${e}`);
    return [];
  }
};

// Process in parallel batches of 10
const BATCH_SIZE = 10;
const allJobs = [];

for (let i = 0; i < combinations.length; i += BATCH_SIZE) {
  const batch = combinations.slice(i, i + BATCH_SIZE);
  const results = await Promise.all(batch.map(fetchJobs));
  results.forEach(jobs => allJobs.push(...jobs));

  // Small delay between batches to avoid overwhelming jobspy
  if (i + BATCH_SIZE < combinations.length) {
    sleep(100)  
  }
}

// Deduplicate by job_url
const seen = new Set();
const unique = allJobs.filter(job => {
  if (seen.has(job.job_url)) return false;
  seen.add(job.job_url);
  return true;
});

return unique.map(job => ({ json: job }));

const items = $input.all();
const originalJobs = $('Fetch All Jobs').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const response = items[i].json;

  let text = '';
  if (response.content && Array.isArray(response.content)) {
    text = response.content[0]?.text || '';
  }

  let isRelevant = false;
  try {
    isRelevant = JSON.parse(text.trim()).relevant === true;
  } catch (e) {
    isRelevant = text.includes('"relevant": true') || text.includes('"relevant":true');
  }

  if (!isRelevant) continue;

  results.push({ json: originalJobs[i].json });
}

return results;

