const sheetItems  = $input.all();
const newJobItems = $('Parse Filter Output').all();

// Build Set of existing URLs from sheet
const existingUrls = new Set(
  sheetItems
    .map(i => (i.json['Job Link'] || '').trim().toLowerCase())
    .filter(Boolean)
);

// Build Set of company+title combos as second safety check
// catches same job posted under different URLs across sites
const existingKeys = new Set(
  sheetItems
    .map(i => {
      const company = (i.json['Company Name'] || '').trim().toLowerCase();
      const title   = (i.json['Role Title']   || '').trim().toLowerCase();
      return `${company}||${title}`;
    })
    .filter(k => k !== '||')
);

// Filter out already tracked jobs
const newJobs = newJobItems.filter(i => {
  const url     = (i.json.job_url || '').trim().toLowerCase();
  const company = (i.json.company  || '').trim().toLowerCase();
  const title   = (i.json.title    || '').trim().toLowerCase();
  const key     = `${company}||${title}`;

  return !existingUrls.has(url) && !existingKeys.has(key);
});

if (newJobs.length === 0) {
  return [{ json: { skipped: true, message: 'No new jobs today' } }];
}

return newJobs.map(job => ({
  json: {
    ...job.json,
    skipped: false
  }
}));
